import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"【神话典籍综述】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/神术/神话典籍/【神话典籍综述】.md","filePath":"4.资源分区/4.术法/神术/神话典籍/【神话典籍综述】.md"}'),s={name:"4.资源分区/4.术法/神术/神话典籍/【神话典籍综述】.md"};function o(d,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"【神话典籍综述】",tabindex:"-1"},[p("【神话典籍综述】 "),r("a",{class:"header-anchor",href:"#【神话典籍综述】","aria-label":'Permalink to "【神话典籍综述】"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序002")])])],-1),n('<h1 id="神话典籍综述" tabindex="-1">神话典籍综述 <a class="header-anchor" href="#神话典籍综述" aria-label="Permalink to &quot;神话典籍综述&quot;">​</a></h1><p>神话典籍综述：<br> 神话典籍无论是在过去还是如今都被视为禁忌之书，持有者得以从模糊隐晦的只言片语中一窥玄秘而亵渎的知识。大部分的神话典籍在非神话生物阅读时都需要付出一定的永久性代价，以获得对应等级的神话典籍专长，而大多数的神话生物对于神话典籍的态度都是泰然自若。<br> 神话典籍在规则上视为一件传奇的神话之物，而并不属于内在加成，所以不会提供内在的属性加值。在购买者初次购买一种神话典籍后，它所展现出的形态为一本古旧而笨重的空白书籍，购买者须对其进行研读才能获知并掌握其中的神话法术、神话仪式（少部分神话典籍中还包括超科技的运用）。被研读出的内容将自动记录在神话典籍中，由于神话典籍在实质表现上为一本书，所以神话典籍也会被击破、毁坏，当购买者不持有神话典籍时，就无法使用从中研读出的内容，被毁坏的神话典籍会根据当前记录内容的多少而决定重生的时间，一般来说，重生的天数为当前最高等级数+同级记录法术个数（D4C3B2A1S0）。购买者在施放神话典籍中记载的内容时均视为需要“书本”成分，若如此做，则视为获得D1C2B3A4S5点器械增强加值。<br> 研读其中的内容会根据希望研读出的内容的等级决定难度和所需支付的经验值。如没有特殊说明，神话典籍不可越级研读内容。你可以支付8点经验值将神话典籍从书籍形态变为一种合理的且拥有【翻阅】概念的物品。<br> 神话典籍：D+500<br> 会为使用者开放一个能量池。</p><p>D级内容：非神话生物首次研读D级内容时需永久性支付2点意志及其对应上限。<br> 研读每个D级内容需支付10点经验值<br> 特殊的，D级神话典籍会为神话生物在升格仪式中提供5点DC减值<br> 当一本神话典籍的内在总投入经验值超过或达到20点时自动晋升为C级</p><p>C级内容：非神话生物首次研读C级内容时需永久性支付4点意志及其对应上限。<br> 研读每个C级内容需支付20点经验值<br> 特殊的，C级神话典籍会为神话生物在升格仪式中提供10点DC减值<br> 当一本神话典籍的内在总投入经验值超过或达到40点时自动晋升为B级</p><p>B级内容：非神话生物首次研读B级内容时需永久性支付8点意志及其对应上限。<br> 研读每个B级内容需支付40点经验值<br> 特殊的，B级神话典籍会为神话生物在升格仪式中提供20点DC减值<br> 当一本神话典籍的内在总投入经验值超过或达到80点时自动晋升为A级</p><p>A级内容：非神话生物首次研读A级内容时需永久性支付16点意志及其对应上限。<br> 研读每个A级内容需支付80点经验值<br> 特殊的，A级神话典籍会为神话生物在升格仪式中提供30点DC减值<br> 当一本神话典籍的内在总投入经验值超过或达到160点时自动晋升为S级</p><p>S级内容：非神话生物首次研读S级内容时需永久性支付24点意志及其对应上限。<br> 研读每个S级内容需支付160点经验值<br> 特殊的，S级神话典籍中每个S级内容会为神话生物在升格仪式中提供50点DC减值</p><p>非神话生物每研读至一个新的等级，就可以在下列神话典籍专长中选择一个对应等级专长获得（D1C2B3A4S5）</p><p>神话典籍独有专长：<br> 这些专长无法购买，仅由神话典籍的研读赠送<br> 注：专长中写出的随机释放指释放法术目标随机或释放法术随机，当释放法术为随机时，释放目标也为随机，但无论如何，若其不为指定自己的法术，则不会随机指定到自己<br> 平衡真理（1）-（5）<br> 1级：术道稽释<br> 在随机释放一道神话典籍内记述的法术时，可以消耗1点对应能量，将那道法术的效果延迟至多3轮释放，需要注意的是，这一行为是法术释放后令其效果延后，角色的施法行为依然存在，因而无法选择施法三轮进行突袭等行为。<br> 2级：秘经编纂<br> 在释放一道神话典籍内记述的法术时，无需满足法术中的姿势与语言前提便可直接消耗动作释放，但释放出的那道法术随机选择目标。<br> 3级：纵法利搏<br> 战斗场景中，每次随机释放神话典籍内的法术时触发一次，仅对于下一次随机释放的法术而言，根据法术等级额外消耗2/4/6/8/10点对应能量，施法检定会根据释放法术的等级获得额外收益（D/C/B/A/S级法术额外获得2/4/8/16/32DP神话加值）<br> 4级：诡圣贤妖<br> 每场景一次，当你进以神话典籍内记述的法术进行随机施法时，攻击出目增加一半。<br> 5级：骇灵魔风<br> 每场景2次，当以典籍内记载的方式随机释放其中的法术/指定目标时，以对释放者最有利的形式选择释放的法术与目标</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const C=a(s,[["render",o]]);export{D as __pageData,C as default};
